WITH payload AS (
  SELECT $RISQQ11${"questions":[{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.1","internal_question_no":"02A.001","question_sort_key":2100100,"question_text":"Is the latest Class Survey Status available, are all Statutory Certificates listed within it valid, is the vessel free of any overdue Conditions of Class, and are all classification and statutory surveys up to date?","guide_to_inspection":"The inspector should attach a PDF copy of the Class Survey Status (the version reviewed and evaluated during the inspection) to\nthe inspection report.\nA finding should be recorded in the following cases:\n1. A short-term certificate has been issued due to any defect or damage to the ship’s structure, machinery, or equipment.\n2. The vessel has any overdue Conditions of Class.\nIn the comments section, include details if the vessel has any Condition of Class, Significant Recommendation, or Memorandum.\nIf the ship has been provided with a letter of dispensation by the Flag State, record the following in the comments:\n1. Expiry date of the dispensation letter\n2. Nature of the deficiency that led to the issuance of the letter\n3 . Corrective actions mandated by the Flag State to ensure compliance.\nThe class survey status shall be available on board and should be dated not more than seven (7) days prior to the date of the\ninspection. Record a Finding if an up-to-date class survey status was not available on board.\nThe Inspector should accept electronic certificates containing the features below:\n1. Validity and consistency with the format and content required by the relevant international convention or instrument, as\napplicable\n2. Protected from edits, modifications, or revisions other than those authorised by the issuer or the Administration\n3. A unique tracking number, and\n4 . A printable and visible symbol that confirms the source of issuance\n(GUIDELINES FOR THE USE OF ELECTRONIC CERTIFICATES, 2016)\nThe inspector may request the Master to demonstrate the validity of the electronic certificate following the instructions\navailable on board the ship.\nIf the Master fails to demonstrate, to the satisfaction of the inspector, that an electronic certificate meets the requirements,\nthe inspector shall record a Finding.\nThe IMSBC Code fitness certificate in accordance with IMSBC Code (2020 Edition) may be issued upon request from owners/\nshipbuilders on voluntary basis from 1 January 2020.\nFor cargoes listed in Table G1 (Cargo newly added and requirements on construction/equipment (IMSBC Code-4th\namendment) as ‘Group A and B’ or ‘Group B’, IMSBC Code (2020 Edition) a fitness certificate will be issued in cases where\nships comply with requirements in Table G1.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":18,"source_page_end":18,"raw_source_text":"Is the latest Class Survey Status available, are all Statutory Certificates listed within it valid,\nis the vessel free of any overdue Conditions of Class, and are all classification and statutory\nsurveys up to date?\nGuide to Inspection\nThe inspector should attach a PDF copy of the Class Survey Status (the version reviewed and evaluated during the inspection) to\nthe inspection report.\nA finding should be recorded in the following cases:\n1. A short-term certificate has been issued due to any defect or damage to the ship’s structure, machinery, or equipment.\n2. The vessel has any overdue Conditions of Class.\nIn the comments section, include details if the vessel has any Condition of Class, Significant Recommendation, or Memorandum.\nIf the ship has been provided with a letter of dispensation by the Flag State, record the following in the comments:\n1. Expiry date of the dispensation letter\n2. Nature of the deficiency that led to the issuance of the letter\n3 . Corrective actions mandated by the Flag State to ensure compliance.\nThe class survey status shall be available on board and should be dated not more than seven (7) days prior to the date of the\ninspection. Record a Finding if an up-to-date class survey status was not available on board.\nThe Inspector should accept electronic certificates containing the features below:\n1. Validity and consistency with the format and content required by the relevant international convention or instrument, as\napplicable\n2. Protected from edits, modifications, or revisions other than those authorised by the issuer or the Administration\n3. A unique tracking number, and\n4 . A printable and visible symbol that confirms the source of issuance\n(GUIDELINES FOR THE USE OF ELECTRONIC CERTIFICATES, 2016)\nThe inspector may request the Master to demonstrate the validity of the electronic certificate following the instructions\navailable on board the ship.\nIf the Master fails to demonstrate, to the satisfaction of the inspector, that an electronic certificate meets the requirements,\nthe inspector shall record a Finding.\nThe IMSBC Code fitness certificate in accordance with IMSBC Code (2020 Edition) may be issued upon request from owners/\nshipbuilders on voluntary basis from 1 January 2020.\nFor cargoes listed in Table G1 (Cargo newly added and requirements on construction/equipment (IMSBC Code-4th\namendment) as ‘Group A and B’ or ‘Group B’, IMSBC Code (2020 Edition) a fitness certificate will be issued in cases where\nships comply with requirements in Table G1.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.2","internal_question_no":"02A.002","question_sort_key":2100200.001,"question_text":"Has the vessel been provided with certificates of financial security for seafarers?","guide_to_inspection":"From 18 January 2017, all ships which are subject to MLC have been required to carry and display on board two\ncertificates confirming that financial security is in place for:\n(a) shipowners’ liabilities for repatriation of crew, essential needs such as food, accommodation, medical care and up to\nfour months’ outstanding contractual wages and entitlements in the event of abandonment (Regulation 2.5, Standard\nA2.5.2 Paragraph 9)\n(b) contractual payments for death or long-term disability due to an occupational injury, illness or hazard set out in the\nemployment agreement or collective agreement (Regulation 4.2, Standard A4.2.1 paragraph 1(b))\n(FAQs: Maritime Labour Convention 2006 As Amended Financial Security Requirements - The Shipowners’ Club, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":18,"source_page_end":18,"raw_source_text":"Has the vessel been provided with certificates of financial security for seafarers? (M)\nGuide to Inspection\nFrom 18 January 2017, all ships which are subject to MLC have been required to carry and display on board two\ncertificates confirming that financial security is in place for:\n(a) shipowners’ liabilities for repatriation of crew, essential needs such as food, accommodation, medical care and up to\nfour months’ outstanding contractual wages and entitlements in the event of abandonment (Regulation 2.5, Standard\nA2.5.2 Paragraph 9)\n(b) contractual payments for death or long-term disability due to an occupational injury, illness or hazard set out in the\nemployment agreement or collective agreement (Regulation 4.2, Standard A4.2.1 paragraph 1(b))\n(FAQs: Maritime Labour Convention 2006 As Amended Financial Security Requirements - The Shipowners’ Club, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.3","internal_question_no":"02A.003","question_sort_key":2100300.002,"question_text":"Can all crew communicate effectively in the working language of the ship?","guide_to_inspection":"Record the common language and the level of English proficiency of the crew on board the vessel.\nOn all ships, to ensure effective crew performance in safety matters, a working language shall be established and recorded in\nthe ship’s logbook. The company, as defined in regulation IX/1, or the Master, as appropriate, shall determine the appropriate\nworking language. Each seafarer shall be required to understand and, where appropriate, give orders and instructions and to\nreport back in that language. If the working language is not an official language of the State whose Flag the ship is entitled to\nfly, all plans and lists required to be posted shall include a translation into the working language.\nOn ships to which SOLAS chapter I applies, English must be used on the bridge as the working language for bridge-to-\nbridge and bridge-to-shore safety communications as well as for communications on board between the pilot and bridge\nwatchkeeping personnel, unless those directly involved in the communication speak a common language other than English.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":19,"source_page_end":19,"raw_source_text":"Can all crew communicate effectively in the working language of the ship? (V)\nGuide to Inspection\nRecord the common language and the level of English proficiency of the crew on board the vessel.\nOn all ships, to ensure effective crew performance in safety matters, a working language shall be established and recorded in\nthe ship’s logbook. The company, as defined in regulation IX/1, or the Master, as appropriate, shall determine the appropriate\nworking language. Each seafarer shall be required to understand and, where appropriate, give orders and instructions and to\nreport back in that language. If the working language is not an official language of the State whose Flag the ship is entitled to\nfly, all plans and lists required to be posted shall include a translation into the working language.\nOn ships to which SOLAS chapter I applies, English must be used on the bridge as the working language for bridge-to-\nbridge and bridge-to-shore safety communications as well as for communications on board between the pilot and bridge\nwatchkeeping personnel, unless those directly involved in the communication speak a common language other than English.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.4","internal_question_no":"02A.004","question_sort_key":2100400.003,"question_text":"Is the vessel’s manning in compliance with the Safe Manning Certificate?","guide_to_inspection":"Record in comments the actual and required manning of the vessel.\nMinimum safe manning is the level of manning that will ensure that a ship is sufficiently, effectively, and efficiently manned\nto provide safety and security of the ship, safe navigation and operations at sea, safe operations in port, prevention of human\ninjury or loss of life, the avoidance of damage to the marine environment and property, and to ensure the welfare and health of\nseafarers through the avoidance of fatigue.\nExcept in ships of limited size or propulsion power (which are not quantified), the determination of the minimum safe\nmanning level should also consider the provision of qualified officers to ensure that it is not necessary for the Master or Chief\nEngineer to keep regular watches by adopting a three-watch system.\n(PRINCIPLES OF SAFE MANNING, IMO Resolution 1047(27) , 2000)\nInspectors should review the crew list and, considering the level of operation at sea and port, assess if there are enough\npersonnel on board to fulfil the following principles of safe manning:\n> Maintain safe navigation by adequate manning of bridge throughout the passage.\n> Mooring, tending mooring at port and unmooring the ship safely.\n> Effective performance of cargo operation to ensure safe carriage of cargo during transit.\n> Performance of on-board functions such as drills, ship security issues, equipment maintenance.\n> Manning levels should be such as to ensure that the time and place available for taking rest periods are appropriate for\nachieving a good quality of rest.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":19,"source_page_end":19,"raw_source_text":"Is the vessel’s manning in compliance with the Safe Manning Certificate? (V)\nGuide to Inspection\nRecord in comments the actual and required manning of the vessel.\nMinimum safe manning is the level of manning that will ensure that a ship is sufficiently, effectively, and efficiently manned\nto provide safety and security of the ship, safe navigation and operations at sea, safe operations in port, prevention of human\ninjury or loss of life, the avoidance of damage to the marine environment and property, and to ensure the welfare and health of\nseafarers through the avoidance of fatigue.\nExcept in ships of limited size or propulsion power (which are not quantified), the determination of the minimum safe\nmanning level should also consider the provision of qualified officers to ensure that it is not necessary for the Master or Chief\nEngineer to keep regular watches by adopting a three-watch system.\n(PRINCIPLES OF SAFE MANNING, IMO Resolution 1047(27) , 2000)\nInspectors should review the crew list and, considering the level of operation at sea and port, assess if there are enough\npersonnel on board to fulfil the following principles of safe manning:\n> Maintain safe navigation by adequate manning of bridge throughout the passage.\n> Mooring, tending mooring at port and unmooring the ship safely.\n> Effective performance of cargo operation to ensure safe carriage of cargo during transit.\n> Performance of on-board functions such as drills, ship security issues, equipment maintenance.\n> Manning levels should be such as to ensure that the time and place available for taking rest periods are appropriate for\nachieving a good quality of rest.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.5","internal_question_no":"02A.005","question_sort_key":2100500.004,"question_text":"Do all personnel maintain rest period/work hours and are the rest hours in compliance with STCW or MLC requirements?","guide_to_inspection":"Record a Finding if:\n> There are two or more consecutive violations by any seafarer on-board in any 30 day period.\n> The vessel’s manager has not been informed at least monthly of compliance levels on board.\n> The work hour records are not to ILO format - Inspector should refer to the IMO/ILO guideline “Guidelines for the\nDevelopment of Tables of Seafarers’ Shipboard Working Arrangements and Formats of Records of Seafarers’ Hours of\nWork or Hours of Rest”.\nEach Administration shall, for the purpose of preventing fatigue:\n> Establish and enforce rest periods for watchkeeping personnel and those whose duties involve designated safety,\nsecurity and prevention of pollution duties in accordance with the provisions of section A-VIII/1 of the STCW Code.\n> All persons who are assigned duty as officer in charge of a watch or as a rating forming part of a watch and those\nwhose duties involve designated safety, prevention of pollutions and security duties shall be provided with a rest period\nof not less than:\n1. minimum of 10 hours of rest in any 24-hour period; and\n2. 77 hours in any 7-day period.\n3. The hours of rest may be divided into no more than two periods, one of which shall be at least 6 hours in length, and the\nintervals between consecutive periods of rest shall not exceed 14 hours.\n> Parties may allow exceptions from the required periods of rest in paragraphs 2 and 3 above provided that the rest period\nis not less than 70 hours in any 7-day period.\nException from the weekly rest period provided for in paragraph 2 shall not be allowed for more than two consecutive weeks.\nThe intervals between the two periods of exceptions onboard shall not be less than twice the duration of the exception.\nThe hours of rest provided for in paragraph 1 may be divided into no more than three periods, one of which shall be at least\nsix hours in length, and neither of the other two shall be less than one hour in length. The intervals between consecutive\nperiods of rest shall not exceed 14 hours. Exceptions shall not extend beyond two 24-hour periods in any 7-day period.\nExceptions shall, as far as possible, take into account the guidance regarding prevention of fatigue in section B-VIII/1.\n( Regulation VIII/1 Fitness for duty STCW 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":20,"source_page_end":20,"raw_source_text":"Do all personnel maintain rest period/work hours and are the rest hours in compliance with\nSTCW or MLC requirements? (V)\nGuide to Inspection\nRecord a Finding if:\n> There are two or more consecutive violations by any seafarer on-board in any 30 day period.\n> The vessel’s manager has not been informed at least monthly of compliance levels on board.\n> The work hour records are not to ILO format - Inspector should refer to the IMO/ILO guideline “Guidelines for the\nDevelopment of Tables of Seafarers’ Shipboard Working Arrangements and Formats of Records of Seafarers’ Hours of\nWork or Hours of Rest”.\nEach Administration shall, for the purpose of preventing fatigue:\n> Establish and enforce rest periods for watchkeeping personnel and those whose duties involve designated safety,\nsecurity and prevention of pollution duties in accordance with the provisions of section A-VIII/1 of the STCW Code.\n> All persons who are assigned duty as officer in charge of a watch or as a rating forming part of a watch and those\nwhose duties involve designated safety, prevention of pollutions and security duties shall be provided with a rest period\nof not less than:\n1. minimum of 10 hours of rest in any 24-hour period; and\n2. 77 hours in any 7-day period.\n3. The hours of rest may be divided into no more than two periods, one of which shall be at least 6 hours in length, and the\nintervals between consecutive periods of rest shall not exceed 14 hours.\n> Parties may allow exceptions from the required periods of rest in paragraphs 2 and 3 above provided that the rest period\nis not less than 70 hours in any 7-day period.\nException from the weekly rest period provided for in paragraph 2 shall not be allowed for more than two consecutive weeks.\nThe intervals between the two periods of exceptions onboard shall not be less than twice the duration of the exception.\nThe hours of rest provided for in paragraph 1 may be divided into no more than three periods, one of which shall be at least\nsix hours in length, and neither of the other two shall be less than one hour in length. The intervals between consecutive\nperiods of rest shall not exceed 14 hours. Exceptions shall not extend beyond two 24-hour periods in any 7-day period.\nExceptions shall, as far as possible, take into account the guidance regarding prevention of fatigue in section B-VIII/1.\n( Regulation VIII/1 Fitness for duty STCW 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.6","internal_question_no":"02A.006","question_sort_key":2100600.005,"question_text":"Has the Master been provided with relevant ship handling training?","guide_to_inspection":"This question applies to large ships or vessels with considerable length or deadweight.If the Master has accumulated 36 months or\nmore of sea service in rank and has served on the same type of vessel for at least the past 12 months, the response to this question\nshould be “Not Applicable.\nMasters with less than 36 months of sea service in rank, or those newly promoted, should complete a ship handling training course\naligned with the objectives of STCW Code B-V/a.\n> It is important that Masters and Chief Officer have had relevant experience and training before assuming duties of Master or\nChief Officer of large ships or ships having unusual manoeuvring and handling characteristics significantly different from those\nin which they have recently served. Such characteristics will generally be found in ships which are of considerable deadweight or\nlength or of special design or of high speed.\n> Before initially assuming command of one of the ships referred to above, the prospective Master should have sufficient and\nappropriate general experience as Master or Chief Officer, and either:\n- Have sufficient and appropriate experience manoeuvring the same ship under supervision or in manoeuvring a ship\nhaving similar characteristics or,\n-Have attended an approved ship handling simulator course on an installation capable of simulating the manoeuvring\ncharacteristics of such a ship.\nTraining may be conducted:\n> Onboard company vessels under formal supervision, documented through a structured competency development process, or\n> At an approved shore-based training facility.\nWhen training is conducted during a parallel voyage prior to assuming command of a vessel with significantly different handling\ncharacteristics, the vessel manager should:\n> Define the required training activities,\n> Ensure these activities are completed by the incoming Master, and\n> Have them assessed and documented by the current Master or a suitably qualified Superintendent before the handover of\ncommand.\nThe vessel manager is responsible for evaluating the handling characteristics of all vessel types under their management and\nidentifying when additional ship handling training is necessary—particularly when a Master is reassigned to a vessel with significantly\ndifferent characteristics from those previously served on.\nEvaluation of vessel handling characteristics should consider:\n> Number and type of propellers/drives,\n> Number and type of rudders,\n> Number and type of thrusters,\n> And not be based solely on vessel size.\nWhere shore-based ship handling training is required, the validity period of the course should be defined, specifying the maximum time\nbefore assignment to a vessel type after which the training should be refreshed or repeated.\nRightShip defines a vessel as ‘large’ or having ‘considerable deadweight or length’ if it exceeds either:\n> 270 meters in length overall (LOA), or\n> 140,000 deadweight tons (DWT).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":20,"source_page_end":21,"raw_source_text":"Has the Master been provided with relevant ship handling training? (V)\nGuide to Inspection\nThis question applies to large ships or vessels with considerable length or deadweight.If the Master has accumulated 36 months or\nmore of sea service in rank and has served on the same type of vessel for at least the past 12 months, the response to this question\nshould be “Not Applicable.\nMasters with less than 36 months of sea service in rank, or those newly promoted, should complete a ship handling training course\naligned with the objectives of STCW Code B-V/a.\n> It is important that Masters and Chief Officer have had relevant experience and training before assuming duties of Master or\nChief Officer of large ships or ships having unusual manoeuvring and handling characteristics significantly different from those\nin which they have recently served. Such characteristics will generally be found in ships which are of considerable deadweight or\nlength or of special design or of high speed.\n> Before initially assuming command of one of the ships referred to above, the prospective Master should have sufficient and\nappropriate general experience as Master or Chief Officer, and either:\n- Have sufficient and appropriate experience manoeuvring the same ship under supervision or in manoeuvring a ship\nhaving similar characteristics or,\n-Have attended an approved ship handling simulator course on an installation capable of simulating the manoeuvring\ncharacteristics of such a ship.\nTraining may be conducted:\n> Onboard company vessels under formal supervision, documented through a structured competency development process, or\n> At an approved shore-based training facility.\nWhen training is conducted during a parallel voyage prior to assuming command of a vessel with significantly different handling\ncharacteristics, the vessel manager should:\n> Define the required training activities,\n> Ensure these activities are completed by the incoming Master, and\n> Have them assessed and documented by the current Master or a suitably qualified Superintendent before the handover of\ncommand.\nThe vessel manager is responsible for evaluating the handling characteristics of all vessel types under their management and\nidentifying when additional ship handling training is necessary—particularly when a Master is reassigned to a vessel with significantly\ndifferent characteristics from those previously served on.\nEvaluation of vessel handling characteristics should consider:\n> Number and type of propellers/drives,\n> Number and type of rudders,\n> Number and type of thrusters,\n> And not be based solely on vessel size.\nWhere shore-based ship handling training is required, the validity period of the course should be defined, specifying the maximum time\nbefore assignment to a vessel type after which the training should be refreshed or repeated.\nRightShip defines a vessel as ‘large’ or having ‘considerable deadweight or length’ if it exceeds either:\n> 270 meters in length overall (LOA), or\n> 140,000 deadweight tons (DWT).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.7","internal_question_no":"02A.007","question_sort_key":2100700.006,"question_text":"Have officers and ratings responsible for cargo handling on ships carrying dangerous and hazardous substances in solid form in bulk, undergone formal training?","guide_to_inspection":"If the ship is not carrying solid bulk cargo, the question should be answered N/A.\nThe course should be conducted according to IMO Model Course 1.45, titled ‘Safe Handling and Transport of Solid Bulk\nCargoes’. The objectives of the course include ensuring that trainees understand the potential dangers that may occur during\nthe loading, carrying, and unloading of solid bulk cargoes. It aims to enhance their awareness of safety and environmental\nprotection, improve their ability to use the IMSBC Code, and help them learn standardized operations to reduce potential\nsafety hazards. This is to ensure the safety of personnel, ships, and cargoes, and to prevent marine environmental pollution.\nA trainee successfully completing this course will be able to:\n> Identify risks associated with the carriage of solid bulk cargoes by sea;\n> Assess the acceptability of consignments for safe shipment, especially Group A solid bulk cargoes;\n> Observe safe working practices in the loading and carriage of solid bulk cargoes;\n> Observe ship and port security regulations related to the loading, carriage, and unloading of solid bulk cargoes; and\n> Supervise the operation process of certain cargoes following regulations in the IMSBC Code .\nUpon successful completion of the course, an appropriate certificate or similar document should be issued to the trainees to\nprove that they have received training in using the IMSBC Code in maritime practice in accordance with IMO Model Course\n1.45.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":21,"source_page_end":21,"raw_source_text":"Have officers and ratings responsible for cargo handling on ships carrying dangerous and hazardous\nsubstances in solid form in bulk, undergone formal training? (V)\nGuide to Inspection\nIf the ship is not carrying solid bulk cargo, the question should be answered N/A.\nThe course should be conducted according to IMO Model Course 1.45, titled ‘Safe Handling and Transport of Solid Bulk\nCargoes’. The objectives of the course include ensuring that trainees understand the potential dangers that may occur during\nthe loading, carrying, and unloading of solid bulk cargoes. It aims to enhance their awareness of safety and environmental\nprotection, improve their ability to use the IMSBC Code, and help them learn standardized operations to reduce potential\nsafety hazards. This is to ensure the safety of personnel, ships, and cargoes, and to prevent marine environmental pollution.\nA trainee successfully completing this course will be able to:\n> Identify risks associated with the carriage of solid bulk cargoes by sea;\n> Assess the acceptability of consignments for safe shipment, especially Group A solid bulk cargoes;\n> Observe safe working practices in the loading and carriage of solid bulk cargoes;\n> Observe ship and port security regulations related to the loading, carriage, and unloading of solid bulk cargoes; and\n> Supervise the operation process of certain cargoes following regulations in the IMSBC Code .\nUpon successful completion of the course, an appropriate certificate or similar document should be issued to the trainees to\nprove that they have received training in using the IMSBC Code in maritime practice in accordance with IMO Model Course\n1.45.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.8","internal_question_no":"02A.008","question_sort_key":2100800.007,"question_text":"Have officers and ratings responsible for cargo handling on ships carrying dangerous and hazardous substances in packaged form, undergone formal training","guide_to_inspection":"If the vessel is not handling packaged dangerous, hazardous, and harmful cargoes (dangerous goods) or was not carrying such\ncargo at the time of inspection or during the previous voyage, respond to this question with N/A.\nThe course should enable trainees to contribute effectively to the preparation and execution of the safe carriage of dangerous\ngoods and marine pollutants by sea. Trainees should understand the legal implications and correctly apply or verify compliance\nwith detailed instructions, including safe packaging, handling, stowage, and segregation of dangerous, hazardous, and harmful\ncargoes. Additionally, they should be aware of the necessary precautions in relation to other cargoes as outlined in the IMDG Code\nand its supplement, as well as the International Convention for Safe Containers (CSC), 1972, insofar as they affect the transport\nof dangerous goods. The course should be designed and delivered to meet the requirements of the IMO model course 1.10,\n“Dangerous, Hazardous, and Harmful Cargoes.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":21,"source_page_end":21,"raw_source_text":"Have officers and ratings responsible for cargo handling on ships carrying dangerous and hazardous\nsubstances in packaged form, undergone formal training (V)?\nGuide to Inspection\nIf the vessel is not handling packaged dangerous, hazardous, and harmful cargoes (dangerous goods) or was not carrying such\ncargo at the time of inspection or during the previous voyage, respond to this question with N/A.\nThe course should enable trainees to contribute effectively to the preparation and execution of the safe carriage of dangerous\ngoods and marine pollutants by sea. Trainees should understand the legal implications and correctly apply or verify compliance\nwith detailed instructions, including safe packaging, handling, stowage, and segregation of dangerous, hazardous, and harmful\ncargoes. Additionally, they should be aware of the necessary precautions in relation to other cargoes as outlined in the IMDG Code\nand its supplement, as well as the International Convention for Safe Containers (CSC), 1972, insofar as they affect the transport\nof dangerous goods. The course should be designed and delivered to meet the requirements of the IMO model course 1.10,\n“Dangerous, Hazardous, and Harmful Cargoes.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.9","internal_question_no":"02A.009","question_sort_key":2100900.008,"question_text":"Has an SMS policy and procedure been established to enforce the STCW Convention and Code requirements for the purpose of preventing drug and alcohol abuse?","guide_to_inspection":"Record in comments,the date of the last drug and alcohol test that was carried out on board either by an independent agency or\nunder controlled conditions by ship’s personnel with specimens being forwarded to an independent agency. Record in comments\nthe date of the last unannounced alcohol test conducted on-board.\nThe drug and alcohol policy should define who it applies to. In most circumstances this should be everyone in the organisation,\nincluding contractor personnel. The company should ensure that its contractors’ policies on drugs and alcohol align with company\npolicy. There may also be reasons to make reference to safety-critical positions/roles or safety-critical work/operations. It should\nalso specify what substances or categories of substance are prohibited under the policy. This should include any psychoactive\nsubstance (i.e. affecting cognitive function), regardless of circumstances of use. Individual countries and jurisdictions may have\ndiffering regulations on the import, stocking, possession, or use of drugs or alcohol, and there may be legal requirements for\ntesting. The policy will need to take this into account and make appropriate stipulations and requirements, especially with respect\nto prohibited behaviours, sampling and testing. These requirements should be made clear to personnel. The policy should also\nrefer to those situations where the use of substances is permitted, specifying what the company will allow and the company’s\nexpectations and requirements with respect to usage and fitness to work. Local regulations should always be considered and\nshould take precedence when defining specific policy parameters. Permitted use may include prescription drugs brought onboard\na ship, with evidence of a valid prescription from a qualified registered medical practitioner or issued from the ship’s medical store\nor the terminal’s clinic.\nThis does not preclude a company from having a zero-alcohol and a zero-drug policy on company premises, ships, etc.\nA drug and alcohol policy should set out clear and consistent expectations regarding conditions of employment, employee\nbehaviour and the consequences of not meeting these expectations. It is recommended that companies set out in their policy a\nclear and consistent legally compliant stand-down procedure for those cases where the drug and/or alcohol test is confirmed\npositive. Employees are expected to follow stand-down orders. Depending on company, role and situation, this could mean\nstanding down from all duties, or standing down from safety critical duties only.\nThe policy should highlight and describe those situations or behaviours where disciplinary or other action will be taken, up to and\nincluding termination of employment.\nTypical examples may include:\n> Using, distributing/selling, or possessing alcohol or drugs at work other than where use\nis permitted.\n> Non-compliance with Standards of Training, Certification and Watchkeeping (STCW) guidance.\n> Being under the influence at work, or otherwise unfit for work, due to any\nprohibited substance.\n> Not complying with stand-down orders given after a positive test result.\n> Refusal to test, interfering with or obstructing a sampling and testing process or otherwise failing to cooperate or comply.\nConsequences should be consistent with local company policy and the law. Since many companies will have operations spanning\ndifferent countries, it may be necessary to adapt the drug and alcohol policy according to legal advice from those jurisdictions.\nCompanies should have a fair review process, ensuring personnel can challenge a positive result. It is recommended to choose\ndrug and alcohol testing programmes with the most appropriate technology for the specific type of organisation. Considerations\nmay include available tests, cost, gender sensitivity, any medical advice, availability of competent persons and laboratories to carry\nout relevant tests, and the practicalities of the sampling processes.\nSpecific legal requirements of the jurisdiction may determine what testing can be done and how it must be done. Provided the legal\nrequirements are met, the procedures should include:\n> Employees must consent to being tested for drugs and alcohol for practical and legal reasons. Should they refuse when an\nemployer has grounds for testing, they should be made aware that they may face disciplinary action.\n> Testing must strictly follow validated and authorised processes, to ensure samples cannot be contaminated or tampered\nwith, and that testing procedures and analyses are accurate. It is recommended that companies follow a legally defensible\nprocess. This must include adequate training of all parties from sample collection to issuing the validated results, a robust\nchain of custody process, validated testing methods or laboratories, and an MRO process for non - negative (laboratory\npositive) samples.\n> Unannounced testing can be done at the workplace and can be done by a trained company collecting officer or an external\nparty – for both drugs and alcohol.\n> Unannounced alcohol tests conducted on-board ships or in terminals can be initiated by the ship’s Master, the Terminal\nManager or the company. Initiation by the company is important to ensure there is the ability to test the Master or the\nTerminal Manager.\nAlcohol Limits under the STCW Code: Understanding Blood vs. Breath Measurements\nThe STCW Code stipulates:\n1- A limit of not greater than 0.05% BAC (blood), or\n2- 0.25 mg/L alcohol in breath.\nBlood and breath alcohol concentrations are measured in different biological mediums (blood vs. exhaled air). While there is a\ncommon conversion ratio (approximately 2100:1), it is not exact and can vary by individual physiology, temperature, and testing\nmethod. Relying on conversions can lead to compliance gaps or legal disputes, especially during audits or investigations.\nIt is recommended that the company’s alcohol and drug policy clearly define separate limits for blood and breath alcohol\nconcentration in line with STCW A-VIII/1 requirements, rather than relying on conversions between measurement units.\nAdditionally, guidance should be provided for interpreting urine analysis results in consultation with the testing contractor,\nrecognising the current absence of statutory limits for this medium.\nThe following types of drug and alcohol screening at a minimum are recommended:\nTypes of testing Frequency\nPre-employment As required\nFor cause/reasonable suspicion/post-accident or incident As required\n*Unannounced random/periodical Once per year OR sufficient to serve as a deterrent to\nmisuse\nReturn to work/post-treatment As required\n*Legal requirements:\nThe inspector is not required to verify whether the vessel’s manager has sought legal advice in the preparation of the company’s\ndrug and alcohol policy and procedures during the physical inspection.\nShip manager with offices in multiple jurisdictions are advised to seek legal advice, as there may be country-specific restrictions\non the importation, possession, storage, or use of drugs and alcohol. Additionally, legal obligations concerning drug and alcohol\ntesting may vary by location. Non-compliance with such regulations can result in legal consequences for both the employer and\nthe employee.\nGiven that drug and alcohol policies and testing programmes may have implications under human rights, employment, criminal,\noccupational health and safety, and data protection laws, it is strongly recommended that such policies be developed with input\nfrom legal professionals, drug and alcohol programme specialists, human resources personnel, and occupational health or medical\nexperts.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":22,"source_page_end":23,"raw_source_text":"Has an SMS policy and procedure been established to enforce the STCW Convention and Code requirements\nfor the purpose of preventing drug and alcohol abuse? (V & M)\nGuide to Inspection\nRecord in comments,the date of the last drug and alcohol test that was carried out on board either by an independent agency or\nunder controlled conditions by ship’s personnel with specimens being forwarded to an independent agency. Record in comments\nthe date of the last unannounced alcohol test conducted on-board.\nThe drug and alcohol policy should define who it applies to. In most circumstances this should be everyone in the organisation,\nincluding contractor personnel. The company should ensure that its contractors’ policies on drugs and alcohol align with company\npolicy. There may also be reasons to make reference to safety-critical positions/roles or safety-critical work/operations. It should\nalso specify what substances or categories of substance are prohibited under the policy. This should include any psychoactive\nsubstance (i.e. affecting cognitive function), regardless of circumstances of use. Individual countries and jurisdictions may have\ndiffering regulations on the import, stocking, possession, or use of drugs or alcohol, and there may be legal requirements for\ntesting. The policy will need to take this into account and make appropriate stipulations and requirements, especially with respect\nto prohibited behaviours, sampling and testing. These requirements should be made clear to personnel. The policy should also\nrefer to those situations where the use of substances is permitted, specifying what the company will allow and the company’s\nexpectations and requirements with respect to usage and fitness to work. Local regulations should always be considered and\nshould take precedence when defining specific policy parameters. Permitted use may include prescription drugs brought onboard\na ship, with evidence of a valid prescription from a qualified registered medical practitioner or issued from the ship’s medical store\nor the terminal’s clinic.\nThis does not preclude a company from having a zero-alcohol and a zero-drug policy on company premises, ships, etc.\nA drug and alcohol policy should set out clear and consistent expectations regarding conditions of employment, employee\nbehaviour and the consequences of not meeting these expectations. It is recommended that companies set out in their policy a\nclear and consistent legally compliant stand-down procedure for those cases where the drug and/or alcohol test is confirmed\npositive. Employees are expected to follow stand-down orders. Depending on company, role and situation, this could mean\nstanding down from all duties, or standing down from safety critical duties only.\nThe policy should highlight and describe those situations or behaviours where disciplinary or other action will be taken, up to and\nincluding termination of employment.\nTypical examples may include:\n> Using, distributing/selling, or possessing alcohol or drugs at work other than where use\nis permitted.\n> Non-compliance with Standards of Training, Certification and Watchkeeping (STCW) guidance.\n> Being under the influence at work, or otherwise unfit for work, due to any\nprohibited substance.\n> Not complying with stand-down orders given after a positive test result.\n> Refusal to test, interfering with or obstructing a sampling and testing process or otherwise failing to cooperate or comply.\nConsequences should be consistent with local company policy and the law. Since many companies will have operations spanning\ndifferent countries, it may be necessary to adapt the drug and alcohol policy according to legal advice from those jurisdictions.\nCompanies should have a fair review process, ensuring personnel can challenge a positive result. It is recommended to choose\ndrug and alcohol testing programmes with the most appropriate technology for the specific type of organisation. Considerations\nmay include available tests, cost, gender sensitivity, any medical advice, availability of competent persons and laboratories to carry\nout relevant tests, and the practicalities of the sampling processes.\nSpecific legal requirements of the jurisdiction may determine what testing can be done and how it must be done. Provided the legal\nrequirements are met, the procedures should include:\n> Employees must consent to being tested for drugs and alcohol for practical and legal reasons. Should they refuse when an\nemployer has grounds for testing, they should be made aware that they may face disciplinary action.\n> Testing must strictly follow validated and authorised processes, to ensure samples cannot be contaminated or tampered\nwith, and that testing procedures and analyses are accurate. It is recommended that companies follow a legally defensible\nprocess. This must include adequate training of all parties from sample collection to issuing the validated results, a robust\nchain of custody process, validated testing methods or laboratories, and an MRO process for non - negative (laboratory\npositive) samples.\n> Unannounced testing can be done at the workplace and can be done by a trained company collecting officer or an external\nparty – for both drugs and alcohol.\n> Unannounced alcohol tests conducted on-board ships or in terminals can be initiated by the ship’s Master, the Terminal\nManager or the company. Initiation by the company is important to ensure there is the ability to test the Master or the\nTerminal Manager.\nAlcohol Limits under the STCW Code: Understanding Blood vs. Breath Measurements\nThe STCW Code stipulates:\n1- A limit of not greater than 0.05% BAC (blood), or\n2- 0.25 mg/L alcohol in breath.\nBlood and breath alcohol concentrations are measured in different biological mediums (blood vs. exhaled air). While there is a\ncommon conversion ratio (approximately 2100:1), it is not exact and can vary by individual physiology, temperature, and testing\nmethod. Relying on conversions can lead to compliance gaps or legal disputes, especially during audits or investigations.\nIt is recommended that the company’s alcohol and drug policy clearly define separate limits for blood and breath alcohol\nconcentration in line with STCW A-VIII/1 requirements, rather than relying on conversions between measurement units.\nAdditionally, guidance should be provided for interpreting urine analysis results in consultation with the testing contractor,\nrecognising the current absence of statutory limits for this medium.\nThe following types of drug and alcohol screening at a minimum are recommended:\nTypes of testing Frequency\nPre-employment As required\nFor cause/reasonable suspicion/post-accident or incident As required\n*Unannounced random/periodical Once per year OR sufficient to serve as a deterrent to\nmisuse\nReturn to work/post-treatment As required\n*Legal requirements:\nThe inspector is not required to verify whether the vessel’s manager has sought legal advice in the preparation of the company’s\ndrug and alcohol policy and procedures during the physical inspection.\nShip manager with offices in multiple jurisdictions are advised to seek legal advice, as there may be country-specific restrictions\non the importation, possession, storage, or use of drugs and alcohol. Additionally, legal obligations concerning drug and alcohol\ntesting may vary by location. Non-compliance with such regulations can result in legal consequences for both the employer and\nthe employee.\nGiven that drug and alcohol policies and testing programmes may have implications under human rights, employment, criminal,\noccupational health and safety, and data protection laws, it is strongly recommended that such policies be developed with input\nfrom legal professionals, drug and alcohol programme specialists, human resources personnel, and occupational health or medical\nexperts.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.10","internal_question_no":"02A.010","question_sort_key":2101000.009,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":23,"source_page_end":23,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.11","internal_question_no":"02A.011","question_sort_key":2101100.01,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":23,"source_page_end":23,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.12","internal_question_no":"02A.012","question_sort_key":2101200.011,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":23,"source_page_end":23,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.13","internal_question_no":"02A.013","question_sort_key":2101300.012,"question_text":"Is the officer matrix accurately completed and does it reflect the information on officers and engineers on board the vessel at the time of inspection?","guide_to_inspection":"The inspector should record a finding when the officer matrix has not been updated to reflect the officers who were on board at the\ntime of the inspection. An allowance should be made for any officer who had changed within the previous seven days. If there is\na documented procedure in place and senior officers have been transfered between sister ships, the inspector must not record a\nFinding for a lack of overlap or parallel sailing period.\nThe vessel’s manager shall provide sufficient overlap for Master / Chief Officer and Chief Engineer / Second Engineer to ensure\nthat they are familiar with the vessel’s operation before taking charge, and both senior officers and senior engineers are not\nchanged at the same time.\nThe vessel’s manager is responsible to maintain up-to-date records relating to the officers and engineers on board the\nvessel at the time of inspection. The inspector should have a copy of the updated officer matrix and check the tour on board,\nqualifications and experience of officers and engineers against the crew list and seaman books. The actual details of Master,\nChief Engineer, Chief Officer and Second Engineer / First Engineer must be checked against the data contained in the matrix and\na Finding shall be recorded for inaccurate updates.\nRandom checks must be made of the actual records applicable to junior officers and junior engineers.\nA seafarer may hold a Certificate of Receipt of Application (CRA) and a valid national STCW Certificate, for a period not exceeding\nthree (3) months while an application for the STCW Endorsement Certificate is being processed. The inspector shall check the\nvalidity of CRAs.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":23,"source_page_end":23,"raw_source_text":"Is the officer matrix accurately completed and does it reflect the information on officers and engineers on\nboard the vessel at the time of inspection? (V)\nGuide to Inspection\nThe inspector should record a finding when the officer matrix has not been updated to reflect the officers who were on board at the\ntime of the inspection. An allowance should be made for any officer who had changed within the previous seven days. If there is\na documented procedure in place and senior officers have been transfered between sister ships, the inspector must not record a\nFinding for a lack of overlap or parallel sailing period.\nThe vessel’s manager shall provide sufficient overlap for Master / Chief Officer and Chief Engineer / Second Engineer to ensure\nthat they are familiar with the vessel’s operation before taking charge, and both senior officers and senior engineers are not\nchanged at the same time.\nThe vessel’s manager is responsible to maintain up-to-date records relating to the officers and engineers on board the\nvessel at the time of inspection. The inspector should have a copy of the updated officer matrix and check the tour on board,\nqualifications and experience of officers and engineers against the crew list and seaman books. The actual details of Master,\nChief Engineer, Chief Officer and Second Engineer / First Engineer must be checked against the data contained in the matrix and\na Finding shall be recorded for inaccurate updates.\nRandom checks must be made of the actual records applicable to junior officers and junior engineers.\nA seafarer may hold a Certificate of Receipt of Application (CRA) and a valid national STCW Certificate, for a period not exceeding\nthree (3) months while an application for the STCW Endorsement Certificate is being processed. The inspector shall check the\nvalidity of CRAs.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.14","internal_question_no":"02A.014","question_sort_key":2101400.013,"question_text":"If ECDIS is fitted on board, has the Master and Navigation Officers been familiarised with the ECDIS equipment installed on board, and were objective evidences of this familiarisation available?","guide_to_inspection":"Inspector to record how the familiarisation training was carried out. ECDIS familiarisation should be provided to all on-signing deck\nofficers before they take an independent navigation watch, and each time they join any vessel. (Recommendations on Usage of\nECDIS and Preventing Incident, 2020)\nThe STCW Code contains requirements for approved training on ECDIS. In cases where the approved training has not been\ncompleted, a limitation shall be included on the certificate and endorsements issued to the seafarer.\nWhere such a limitation is not specified, the certificate and endorsements are evidence of having successfully completed the\nrequired approved training and that the standard of competence has been achieved.\nNo requirement exists for the approved training on ECDIS equipment to be type specific. The knowledge, understanding and\nproficiency required to be demonstrated is generalized to ensure seafarers have the necessary skills for basic operation of all types\nof equipment.\nIn accordance with regulation, I/14, companies are responsible for ensuring that seafarers employed on their ships are familiarized\nwith the installed equipment, including ECDIS.\nIt is agreed that seafarers required to have training in the use of ECDIS:\n1. Should not be required to provide documentation of training in ECDIS that is specific to the installed equipment; and\n2. Are required to be familiarised with the ECDIS equipment installed on board.\n(STCW.7/Circ.24/Rev.1, 2017 )\nDeck officers who hold a Certificate of Competency with validity over 01 January 2017, in accordance to regulations II/1 and II/2 of\nthe annex to the STCW-Convention and without an ECDIS limitation, fulfil the requirement of generic ECDIS-training.\nThe vessel’s manager can consider a wide variety of options for achieving familiarisation both on-board and ashore. These include\nbut are not limited to:\n> Shore based manufacturer training followed by installation-specific familiarisation onboard.\n> Independent training on specific systems followed by installation specific familiarisation.\n> Computer Based Training (CBT), followed by installation-specific familiarisation on-board.\n> Internet / Intranet Based Training (eLearning) followed by installation specific Familiarisation on-board.\n> On-board training by appropriately trained crew or training personnel.\n> Manufacturer provided training mode on the ECDIS, followed by installation-specific familiarisation on-board.\n> Company bridge procedures and manuals.\nRegardless of the method(s) used, it is essential that all watch keeping officers are competent in the use of the on-board ECDIS\nprior to taking charge of a navigational watch and remain so thereafter.\n(Industry Recommendations for ECDIS Familiarisation, 2012)\nThe SMS should include a procedure to ensure the Master and all watchkeeping officers familiarise themselves with the use of the\nECDIS equipment installed on board prior to taking an independent navigational watch. The procedures for familiarisation should\ninclude:\n> The time scale for the familiarisation.\n> The method(s) of familiarisation with the ECDIS equipment.\n> The location of the familiarisation, whether on board or ashore.\n> The identity of the appropriately trained crew or training personnel authorised to deliver the familiarisation.\n> The method of evaluation of the familiarisation upon completion, and before taking an independent navigational watch.\n> The records to be maintained.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":24,"source_page_end":24,"raw_source_text":"If ECDIS is fitted on board, has the Master and Navigation Officers been familiarised with the ECDIS\nequipment installed on board, and were objective evidences of this familiarisation available? (V)\nGuide to Inspection\nInspector to record how the familiarisation training was carried out. ECDIS familiarisation should be provided to all on-signing deck\nofficers before they take an independent navigation watch, and each time they join any vessel. (Recommendations on Usage of\nECDIS and Preventing Incident, 2020)\nThe STCW Code contains requirements for approved training on ECDIS. In cases where the approved training has not been\ncompleted, a limitation shall be included on the certificate and endorsements issued to the seafarer.\nWhere such a limitation is not specified, the certificate and endorsements are evidence of having successfully completed the\nrequired approved training and that the standard of competence has been achieved.\nNo requirement exists for the approved training on ECDIS equipment to be type specific. The knowledge, understanding and\nproficiency required to be demonstrated is generalized to ensure seafarers have the necessary skills for basic operation of all types\nof equipment.\nIn accordance with regulation, I/14, companies are responsible for ensuring that seafarers employed on their ships are familiarized\nwith the installed equipment, including ECDIS.\nIt is agreed that seafarers required to have training in the use of ECDIS:\n1. Should not be required to provide documentation of training in ECDIS that is specific to the installed equipment; and\n2. Are required to be familiarised with the ECDIS equipment installed on board.\n(STCW.7/Circ.24/Rev.1, 2017 )\nDeck officers who hold a Certificate of Competency with validity over 01 January 2017, in accordance to regulations II/1 and II/2 of\nthe annex to the STCW-Convention and without an ECDIS limitation, fulfil the requirement of generic ECDIS-training.\nThe vessel’s manager can consider a wide variety of options for achieving familiarisation both on-board and ashore. These include\nbut are not limited to:\n> Shore based manufacturer training followed by installation-specific familiarisation onboard.\n> Independent training on specific systems followed by installation specific familiarisation.\n> Computer Based Training (CBT), followed by installation-specific familiarisation on-board.\n> Internet / Intranet Based Training (eLearning) followed by installation specific Familiarisation on-board.\n> On-board training by appropriately trained crew or training personnel.\n> Manufacturer provided training mode on the ECDIS, followed by installation-specific familiarisation on-board.\n> Company bridge procedures and manuals.\nRegardless of the method(s) used, it is essential that all watch keeping officers are competent in the use of the on-board ECDIS\nprior to taking charge of a navigational watch and remain so thereafter.\n(Industry Recommendations for ECDIS Familiarisation, 2012)\nThe SMS should include a procedure to ensure the Master and all watchkeeping officers familiarise themselves with the use of the\nECDIS equipment installed on board prior to taking an independent navigational watch. The procedures for familiarisation should\ninclude:\n> The time scale for the familiarisation.\n> The method(s) of familiarisation with the ECDIS equipment.\n> The location of the familiarisation, whether on board or ashore.\n> The identity of the appropriately trained crew or training personnel authorised to deliver the familiarisation.\n> The method of evaluation of the familiarisation upon completion, and before taking an independent navigational watch.\n> The records to be maintained.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"02A","section_number":2,"section_letter":"A","section_title":"Certification and personnel management","printed_question_no":"2.15","internal_question_no":"02A.015","question_sort_key":2101500.014,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":24,"source_page_end":24,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.1","internal_question_no":"03A.001","question_sort_key":3100100.015,"question_text":"Is practical guidance on navigational safety incorporated in the vessel manager’s navigation instruction / procedures and are officer’s familiar with the company’s navigation procedures?","guide_to_inspection":"Masters, Officers, and Engineers should be familiar with the utilisation of the override function of engine power limiters. They\nshould also understand that the activation of this override may be necessary while navigating in pilotage waters.\nThe practical guidance on navigational safety shall include the following:\n> Allocation of bridge watch keeping duties and responsibilities.\n> Procedures for passage planning and navigation, including departures from the passage plan.\n> Chart and nautical publication update and correction procedures.\n> ECDIS procedure (including chart and software updates).\n> Procedures to ensure that all essential navigation equipment and main and auxiliary machinery are available\nand fully operational.\n> Ship position reporting procedures.\n> Accident and near miss reporting procedures.\n> Recording of relevant events and Voyage Data Recorder (VDR) policy.\n> Use of Bridge Navigational Watch Alarm System (BNWAS) modes (automatic, manual, on and off) and procedures for\nensuring correct operation.\n> Bridge access and distraction prevention procedures.\n> Procedures for familiarisation and effective handover when crew changes occur.\n> Training and drill requirements.\n> A system for identifying particular training needs.\n> A procedure for when to call the Master to the bridge.\n(Bridge Procedures Guide 2022)\nThe ECDIS procedure should include the following:\n> Voyage planning and execution\n> Watch-keeping with ECDIS\n> Ensuring against over-reliance on ECDIS\n> Chart Maintenance\n> Departure and Arrival checks\n> ECDIS failure and backup system\n> Safety settings\n> The use and reliability of CATZOC\n> ECDIS display layers for various navigation conditions.\n> Managing manual layers to ensure current important information is available and out-of-date material is archived or\nremoved.\n> Display T&Ps NMs and use of AIO function.\n> Where there is no appropriate safety contour available on the ENC\n> Depth contour shading: two shade versus four-shade\n> Define the XTC for various sea area, such as pilotage water, confined waters, coastal waters, and open water, for each\nleg of voyage.\n> Post voyage review, so that any hazards or useful information discovered can be incorporated into future passage\nplans.\n> The route validation\n> A protocol for naming and identifying saved routes to avoid selecting and incorrect route.\n> The frequency of, and preferred method for, position verification while using ECDIS.\nWhere ECDIS is being used as the primary means of navigation it must be clearly stated as such by the company and a policy\nin the SMS.(Admiralty guide to ECDIS implementation, policy, and procedures, 2016)\nA checklist should be established with clear instructions on how to deal with sensory input failure of ECDIS and how it may\naffect safe navigation. This checklist should be kept in bridge.\n(ECDIS LTD, 2019)\nAnchoring procedures must be incorporated in the navigation procedure and shall provide guidance on the following:\n> How to select a good anchorage location, planning the anchoring position and approach in different weathers and\nvisibility condition; bridge team management; traffic density, negotiating overcrowded anchorages with additional risks\nof collision; safety of swing room, under keel clearance\n> Keeping a safe anchor watch, including position-keeping, proper use of radar and GPS guard rings/alarms. OOW use of\nmain engine.\n> The minimum requirement for the Master’s Bridge Orders.\n> When to have the engineers on stand-by, the engine room manned, and the main engines on standby or ready for\nimmediate use.\n> Amount of cable, scope, holding ground, anchor holding power, proximity of shoreline, dangers of dragging anchor, and\nrisk of collision and grounding.\n> When the vessel is in ballast condition, the use of additional ballast.\n> The use of two anchors\n> The limitations on the anchoring equipment under heavy stress\n> The use of anchors in an emergency\n> Deep water anchoring\n> Recognising when a dangerous situation is developing when at anchor and when to move\n> Taking early and effective action\n> Factors affecting a vessel when at anchor in heavy weather, including yawing and snatching\n> Putting to sea in the advent of adverse and severe weather\n(Standard Safety Bulletin on Safe Anchoring, 2008)\nSpecial consideration should be taken to create a backup of ECDIS data on a regular basis so any part of the passage could\nbe reviewed. The company SMS should include frequency and arrangement of ECDIS data backup.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe SMS should incorporate a procedure to ensure the integration of the Pilot, or similar roles such as the Mooring\nMaster, Lightering Master, Marine Advisor, Deep Sea Pilot, etc., into the bridge team. This procedure should involve\nthe documentation and discussion of specific information before any transfer of conn or responsibility takes place.\nThe information should include, but not be limited to:\n> The vessel’s particulars and maneuvering characteristics.\n> The planned passage.\n> The review of the ECDIS and the status of safety depth alarms and layers in use.\n> The use of any navigational aids provided by the pilot.\n> Mooring and/or anchoring requirements.\n> Towage and/or tug assistance.\n> Under keel clearance.\n> Relevant defects and/or constraints.\nThe Master and the Pilot exchange should be documented, discussed, and agreed upon before any transfer of conn\nor responsibility occurs. This Master/Pilot exchange should be repeated whenever there is a change of pilot.\nNavigation officers should be aware of the actions required in the event of single or multiple ECDIS failures.\nThis awareness can be achieved by incorporating familiarisation with such contingency plans into the ECDIS\nfamiliarisation checklist or by conducting routine drills. Inspectors should record a finding if the bridge team are\nunfamiliar with the company’s contingency plans for ECDIS failures.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":25,"source_page_end":26,"raw_source_text":"Is practical guidance on navigational safety incorporated in the vessel manager’s navigation instruction /\nprocedures and are officer’s familiar with the company’s navigation procedures? (V)\nGuide to Inspection\nMasters, Officers, and Engineers should be familiar with the utilisation of the override function of engine power limiters. They\nshould also understand that the activation of this override may be necessary while navigating in pilotage waters.\nThe practical guidance on navigational safety shall include the following:\n> Allocation of bridge watch keeping duties and responsibilities.\n> Procedures for passage planning and navigation, including departures from the passage plan.\n> Chart and nautical publication update and correction procedures.\n> ECDIS procedure (including chart and software updates).\n> Procedures to ensure that all essential navigation equipment and main and auxiliary machinery are available\nand fully operational.\n> Ship position reporting procedures.\n> Accident and near miss reporting procedures.\n> Recording of relevant events and Voyage Data Recorder (VDR) policy.\n> Use of Bridge Navigational Watch Alarm System (BNWAS) modes (automatic, manual, on and off) and procedures for\nensuring correct operation.\n> Bridge access and distraction prevention procedures.\n> Procedures for familiarisation and effective handover when crew changes occur.\n> Training and drill requirements.\n> A system for identifying particular training needs.\n> A procedure for when to call the Master to the bridge.\n(Bridge Procedures Guide 2022)\nThe ECDIS procedure should include the following:\n> Voyage planning and execution\n> Watch-keeping with ECDIS\n> Ensuring against over-reliance on ECDIS\n> Chart Maintenance\n> Departure and Arrival checks\n> ECDIS failure and backup system\n> Safety settings\n> The use and reliability of CATZOC\n> ECDIS display layers for various navigation conditions.\n> Managing manual layers to ensure current important information is available and out-of-date material is archived or\nremoved.\n> Display T&Ps NMs and use of AIO function.\n> Where there is no appropriate safety contour available on the ENC\n> Depth contour shading: two shade versus four-shade\n> Define the XTC for various sea area, such as pilotage water, confined waters, coastal waters, and open water, for each\nleg of voyage.\n> Post voyage review, so that any hazards or useful information discovered can be incorporated into future passage\nplans.\n> The route validation\n> A protocol for naming and identifying saved routes to avoid selecting and incorrect route.\n> The frequency of, and preferred method for, position verification while using ECDIS.\nWhere ECDIS is being used as the primary means of navigation it must be clearly stated as such by the company and a policy\nin the SMS.(Admiralty guide to ECDIS implementation, policy, and procedures, 2016)\nA checklist should be established with clear instructions on how to deal with sensory input failure of ECDIS and how it may\naffect safe navigation. This checklist should be kept in bridge.\n(ECDIS LTD, 2019)\nAnchoring procedures must be incorporated in the navigation procedure and shall provide guidance on the following:\n> How to select a good anchorage location, planning the anchoring position and approach in different weathers and\nvisibility condition; bridge team management; traffic density, negotiating overcrowded anchorages with additional risks\nof collision; safety of swing room, under keel clearance\n> Keeping a safe anchor watch, including position-keeping, proper use of radar and GPS guard rings/alarms. OOW use of\nmain engine.\n> The minimum requirement for the Master’s Bridge Orders.\n> When to have the engineers on stand-by, the engine room manned, and the main engines on standby or ready for\nimmediate use.\n> Amount of cable, scope, holding ground, anchor holding power, proximity of shoreline, dangers of dragging anchor, and\nrisk of collision and grounding.\n> When the vessel is in ballast condition, the use of additional ballast.\n> The use of two anchors\n> The limitations on the anchoring equipment under heavy stress\n> The use of anchors in an emergency\n> Deep water anchoring\n> Recognising when a dangerous situation is developing when at anchor and when to move\n> Taking early and effective action\n> Factors affecting a vessel when at anchor in heavy weather, including yawing and snatching\n> Putting to sea in the advent of adverse and severe weather\n(Standard Safety Bulletin on Safe Anchoring, 2008)\nSpecial consideration should be taken to create a backup of ECDIS data on a regular basis so any part of the passage could\nbe reviewed. The company SMS should include frequency and arrangement of ECDIS data backup.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe SMS should incorporate a procedure to ensure the integration of the Pilot, or similar roles such as the Mooring\nMaster, Lightering Master, Marine Advisor, Deep Sea Pilot, etc., into the bridge team. This procedure should involve\nthe documentation and discussion of specific information before any transfer of conn or responsibility takes place.\nThe information should include, but not be limited to:\n> The vessel’s particulars and maneuvering characteristics.\n> The planned passage.\n> The review of the ECDIS and the status of safety depth alarms and layers in use.\n> The use of any navigational aids provided by the pilot.\n> Mooring and/or anchoring requirements.\n> Towage and/or tug assistance.\n> Under keel clearance.\n> Relevant defects and/or constraints.\nThe Master and the Pilot exchange should be documented, discussed, and agreed upon before any transfer of conn\nor responsibility occurs. This Master/Pilot exchange should be repeated whenever there is a change of pilot.\nNavigation officers should be aware of the actions required in the event of single or multiple ECDIS failures.\nThis awareness can be achieved by incorporating familiarisation with such contingency plans into the ECDIS\nfamiliarisation checklist or by conducting routine drills. Inspectors should record a finding if the bridge team are\nunfamiliar with the company’s contingency plans for ECDIS failures.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.2","internal_question_no":"03A.002","question_sort_key":3100200.016,"question_text":"Are the requirements of the Master’s standing orders explained to the deck officers, and are bridge order books (Night Order) being completed by the Master and countersigned by the officers?","guide_to_inspection":"For the purpose of this question, the term bridge team refers specifically to the Master and the Officers on navigation watch.\nRecord a Finding if the detail of visibility criteria, calling the Master, minimum CPA and ECDIS display layers for various\nnavigation conditions was not incorporated in the Master’s standing order. The Master shall clearly highlight the potential\nsafety risks involved in VHF radio communication between vessels and reliance on AIS communication information, for the\npurpose of collision avoidance. The VHF or AIS text facility should not be used for collision avoidance purpose. Master shall\nbe called if the vessel is needed to exit the XTC.\nThe Master shall ensure that all situations requiring the Master’s call are documented in the Master standing order in line\nwith the Bridge Procedures Guide checklist C2.17 “calling the Master”. The Master should explain particular requirements to\nthe Bridge team in the Master’s Standing Orders. These orders should be drafted to support the SMS.\nCompany and Masters’ Standing Orders should be read by all Bridge Team members upon joining the ship, signed, and\ndated. A copy of the orders should be available on the bridge for reference.\nIn addition to Master’s Standing Orders, specific instructions will be needed. At least at daily intervals, the Master should\nwrite in the bridge order book what is expected of the OOW for that period. These orders should be signed by each OOW when\ntaking over a watch, to confirm that they have read, understood, and will comply with the orders.\nThe OOW should brief other members of the Bridge Team, as appropriate, on any activities or requirements for the\nforthcoming watch. The Master may also issue night orders for periods when the Master is resting, and specific information\nabout the current leg of the passage should be included in them.\n(Bridge Procedures Guide, 2022)\nThere is an expectation that bridge order book entries are made by the Master at least daily when the vessel is at sea.\nAIS information overlaid on ECDIS should be used as an identification tool and not as a collision avoidance tool.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":26,"source_page_end":26,"raw_source_text":"Are the requirements of the Master’s standing orders explained to the deck officers, and are bridge order\nbooks (Night Order) being completed by the Master and countersigned by the officers? (V & M)\nGuide to Inspection\nFor the purpose of this question, the term bridge team refers specifically to the Master and the Officers on navigation watch.\nRecord a Finding if the detail of visibility criteria, calling the Master, minimum CPA and ECDIS display layers for various\nnavigation conditions was not incorporated in the Master’s standing order. The Master shall clearly highlight the potential\nsafety risks involved in VHF radio communication between vessels and reliance on AIS communication information, for the\npurpose of collision avoidance. The VHF or AIS text facility should not be used for collision avoidance purpose. Master shall\nbe called if the vessel is needed to exit the XTC.\nThe Master shall ensure that all situations requiring the Master’s call are documented in the Master standing order in line\nwith the Bridge Procedures Guide checklist C2.17 “calling the Master”. The Master should explain particular requirements to\nthe Bridge team in the Master’s Standing Orders. These orders should be drafted to support the SMS.\nCompany and Masters’ Standing Orders should be read by all Bridge Team members upon joining the ship, signed, and\ndated. A copy of the orders should be available on the bridge for reference.\nIn addition to Master’s Standing Orders, specific instructions will be needed. At least at daily intervals, the Master should\nwrite in the bridge order book what is expected of the OOW for that period. These orders should be signed by each OOW when\ntaking over a watch, to confirm that they have read, understood, and will comply with the orders.\nThe OOW should brief other members of the Bridge Team, as appropriate, on any activities or requirements for the\nforthcoming watch. The Master may also issue night orders for periods when the Master is resting, and specific information\nabout the current leg of the passage should be included in them.\n(Bridge Procedures Guide, 2022)\nThere is an expectation that bridge order book entries are made by the Master at least daily when the vessel is at sea.\nAIS information overlaid on ECDIS should be used as an identification tool and not as a collision avoidance tool.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.3","internal_question_no":"03A.003","question_sort_key":3100300.017,"question_text":"Is the manoeuvring information for the vessel displayed on the bridge and are bridge logbooks, bell book, radar performance book, and Change of Watch at Sea check list being correctly maintained?","guide_to_inspection":"The OOW shall be familiar with the difference between X-Band (3 cm) and S-Band (10 cm) radars, as well as their\ncharacteristics and limitations, such as the impact of different weather conditions on their performance and shadow\nand blind sectors. For all ships of 100 metres in length and over and all chemical tankers and gas carriers regardless\nof size, a pilot card, wheelhouse poster and manoeuvring booklet should be provided.\n(Provision and display of manoeuvring information on board ships, 2011)\nThe OOW should be familiar with the handling characteristics and stopping distances of the ship. In addition,\nthe OOW should know how these characteristics are affected by the current and anticipated machinery status.\nInformation regarding the manoeuvring characteristics should be recorded on the Pilot Card and on the Wheelhouse\nPoster and the manoeuvring booklet. Please refer to Bridge Procedures Guide Checklists C1.2 and C1.3.\n(Bridge Procedures Guide, 2022)\nAll ships engaged on international voyages shall keep on board a record of navigational activities and incidents\nincluding drills and pre-departure tests. When such information is not maintained in the ship’s logbook, it shall be\nmaintained in another form approved by the Administration.\n(SOLAS 1974, regulations V/26 and V/28.1)\nThe quality of the radar picture needs to be checked regularly. This may be done automatically using a performance\nmonitor.\n(Bridge Procedures Guide, 2022)\nThe following should be recorded in the bridge logbook:\n> Navigational information including positions at regular intervals and method of position fixing, courses steered,\nallowances made for compass error, leeway and set.\n> Record of course, distance and speed made good, and course and distance to go should be completed daily.\n> Full set of routine weather observations, with a report of sea and swell conditions, should be entered at the end\nof each watch.\n> Details of severe weather met during the voyage, and the action taken should be recorded.\n> Full details of any matters which might affect the cargo and its condition.\nRightShip recommends that the performance of the radar(s) when operational should be checked and recorded by\nthe OOW at the end of each watch unless this contradicts the makers recommendations. A numeric, percentage,\ngraphical, or other measurement value should be recorded.\nBefore taking over a navigation watch, the incoming officer should positively confirm the ECDIS configuration against\nthe passage plan requirement. The outgoing officer should highlight any changes to the ECDIS configuration outside\nthe passage plan parameters.\nIf an ECDIS alarm must be disabled for any reason, this should be recorded on a formal tracking form to be handed\nover to subsequent watches and approved by the Master.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe communicated ECDIS configuration by the officer of watch should be documented.\nChange of Watch at Sea checklist should be used as per section C2 (Checklist C2.16) of the Bridge Procedures Guide\nand at any other time required by the SMS.\nRightship recommends that the ECDIS display setting should be incorporated into the Change of Watch at Sea\nchecklist.\nThe following documents described in the appendices to Recommendation on the Provision and Display of\nManoeuvring Information on Board Ships (annex, resolution A.601(15)) should be updated to include the\nmanoeuvring characteristics of the ship when the ship has all shaft and engine power available, and when shaft or\nengine power has been limited:\n.1 the Pilot card;\n.2 the wheelhouse poster; and\n.3 the manoeuvring booklet.\n(Amendments to the 2021 Guidelines on the Shaft / Engine Power Limitation System to Comply with the EEXI\nRequirements and Use of a Power Reserve (Resolution MEPC.335(76)), as amended by Resolution MEPC.375(80))\n(2024))","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":27,"source_page_end":27,"raw_source_text":"Is the manoeuvring information for the vessel displayed on the bridge and are bridge logbooks, bell book,\nradar performance book, and Change of Watch at Sea check list being correctly maintained? (V)\nGuide to Inspection\nThe OOW shall be familiar with the difference between X-Band (3 cm) and S-Band (10 cm) radars, as well as their\ncharacteristics and limitations, such as the impact of different weather conditions on their performance and shadow\nand blind sectors. For all ships of 100 metres in length and over and all chemical tankers and gas carriers regardless\nof size, a pilot card, wheelhouse poster and manoeuvring booklet should be provided.\n(Provision and display of manoeuvring information on board ships, 2011)\nThe OOW should be familiar with the handling characteristics and stopping distances of the ship. In addition,\nthe OOW should know how these characteristics are affected by the current and anticipated machinery status.\nInformation regarding the manoeuvring characteristics should be recorded on the Pilot Card and on the Wheelhouse\nPoster and the manoeuvring booklet. Please refer to Bridge Procedures Guide Checklists C1.2 and C1.3.\n(Bridge Procedures Guide, 2022)\nAll ships engaged on international voyages shall keep on board a record of navigational activities and incidents\nincluding drills and pre-departure tests. When such information is not maintained in the ship’s logbook, it shall be\nmaintained in another form approved by the Administration.\n(SOLAS 1974, regulations V/26 and V/28.1)\nThe quality of the radar picture needs to be checked regularly. This may be done automatically using a performance\nmonitor.\n(Bridge Procedures Guide, 2022)\nThe following should be recorded in the bridge logbook:\n> Navigational information including positions at regular intervals and method of position fixing, courses steered,\nallowances made for compass error, leeway and set.\n> Record of course, distance and speed made good, and course and distance to go should be completed daily.\n> Full set of routine weather observations, with a report of sea and swell conditions, should be entered at the end\nof each watch.\n> Details of severe weather met during the voyage, and the action taken should be recorded.\n> Full details of any matters which might affect the cargo and its condition.\nRightShip recommends that the performance of the radar(s) when operational should be checked and recorded by\nthe OOW at the end of each watch unless this contradicts the makers recommendations. A numeric, percentage,\ngraphical, or other measurement value should be recorded.\nBefore taking over a navigation watch, the incoming officer should positively confirm the ECDIS configuration against\nthe passage plan requirement. The outgoing officer should highlight any changes to the ECDIS configuration outside\nthe passage plan parameters.\nIf an ECDIS alarm must be disabled for any reason, this should be recorded on a formal tracking form to be handed\nover to subsequent watches and approved by the Master.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nThe communicated ECDIS configuration by the officer of watch should be documented.\nChange of Watch at Sea checklist should be used as per section C2 (Checklist C2.16) of the Bridge Procedures Guide\nand at any other time required by the SMS.\nRightship recommends that the ECDIS display setting should be incorporated into the Change of Watch at Sea\nchecklist.\nThe following documents described in the appendices to Recommendation on the Provision and Display of\nManoeuvring Information on Board Ships (annex, resolution A.601(15)) should be updated to include the\nmanoeuvring characteristics of the ship when the ship has all shaft and engine power available, and when shaft or\nengine power has been limited:\n.1 the Pilot card;\n.2 the wheelhouse poster; and\n.3 the manoeuvring booklet.\n(Amendments to the 2021 Guidelines on the Shaft / Engine Power Limitation System to Comply with the EEXI\nRequirements and Use of a Power Reserve (Resolution MEPC.335(76)), as amended by Resolution MEPC.375(80))\n(2024))","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.4","internal_question_no":"03A.004","question_sort_key":3100400.018,"question_text":"Have operational checks on navigational equipment been done and are checklists being effectively completed when preparing for sea and prior to port entry?","guide_to_inspection":"Operational checks on navigational equipment should be undertaken when preparing for sea and prior to port entry as per\nsection C ( Checklists C2.1,C2.6 and C2.7) of the Bridge Procedures Guide and at any other time required by the SMS.\nBefore entering restricted or coastal waters, it is important also to check that full control of engine and steering function is available.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":28,"source_page_end":28,"raw_source_text":"Have operational checks on navigational equipment been done and are checklists being effectively\ncompleted when preparing for sea and prior to port entry? (V)\nGuide to Inspection\nOperational checks on navigational equipment should be undertaken when preparing for sea and prior to port entry as per\nsection C ( Checklists C2.1,C2.6 and C2.7) of the Bridge Procedures Guide and at any other time required by the SMS.\nBefore entering restricted or coastal waters, it is important also to check that full control of engine and steering function is available.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.5","internal_question_no":"03A.005","question_sort_key":3100500.019,"question_text":"Are there records indicating that routine tests and checks of bridge equipment are being undertaken regularly?","guide_to_inspection":"Daily tests and checks of bridge equipment should be undertaken, including the following:\n> Manual steering should be tested at least once per watch (as per Checklist C2.1 of BPG).\n> Gyro and magnetic compass errors should be checked and recorded at least once a watch when this is possible.\n> The synchronisation of all compass repeaters, including repeaters at the emergency steering position, should be regularly\nchecked.\n> To ensure adequate performance, information from electronic equipment should always be compared and verified against\ninformation from different independent sources; and\n> All available positioning systems and sources (GNSS, DGNSS, satellite communications terminals with integrated GNSS, and\nterrestrial radio navigation aids) should be cross checked.\nChecks should confirm that the equipment is functioning properly and that it is successfully communicating with any other bridge\nsystem to which it is connected:\n> Built-in test facilities should be used frequently, including alarm self-test functions.\n> Configuration settings should be checked and confirmed to be in accordance with the SMS and the passage plan; and\n> Operational settings and alarms should be correctly set and checked on the equipment and/or the BNWAS.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":28,"source_page_end":28,"raw_source_text":"Are there records indicating that routine tests and checks of bridge equipment are being\nundertaken regularly? (V)\nGuide to Inspection\nDaily tests and checks of bridge equipment should be undertaken, including the following:\n> Manual steering should be tested at least once per watch (as per Checklist C2.1 of BPG).\n> Gyro and magnetic compass errors should be checked and recorded at least once a watch when this is possible.\n> The synchronisation of all compass repeaters, including repeaters at the emergency steering position, should be regularly\nchecked.\n> To ensure adequate performance, information from electronic equipment should always be compared and verified against\ninformation from different independent sources; and\n> All available positioning systems and sources (GNSS, DGNSS, satellite communications terminals with integrated GNSS, and\nterrestrial radio navigation aids) should be cross checked.\nChecks should confirm that the equipment is functioning properly and that it is successfully communicating with any other bridge\nsystem to which it is connected:\n> Built-in test facilities should be used frequently, including alarm self-test functions.\n> Configuration settings should be checked and confirmed to be in accordance with the SMS and the passage plan; and\n> Operational settings and alarms should be correctly set and checked on the equipment and/or the BNWAS.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.6","internal_question_no":"03A.006","question_sort_key":3100600.02,"question_text":"Has the Master/Pilot information exchange been taking place effectively and is the standard pilot card being completed as required?","guide_to_inspection":"The Officer should record the time when the Master/Pilot information exchange is completed. If different, the time of the transfer\nof conn between the Master and Pilot should also be recorded. Additionally, the time of the transfer of conn between Pilots, and if\napplicable, between the Pilot and Master on an outbound passage, should be recorded.\nThe Pilot card should clearly indicate whether a power limiter is engaged, the time necessary to override the power limitation systems,\nand the ship’s maximum power capacity, both with and without the application of the limiter.\nWhile navigating in pilotage waters, the main engine shall be readily available to respond immediately to the full range of manoeuvring\ncommands as outlined in the Pilot card.\nThe pilot and the Master should exchange information regarding the pilot’s intentions, the ship’s characteristics, and operational factor\nas soon as practicable after the pilot has boarded the ship.\nFor an effective Master/Pilot information exchange, use should be made of the MPX checklist (Checklist C1.1 of Bridge Procedures\nGuide). It is essential that the MPX result in clear and effective communication and should cover:\n> Presentation of a completed standard Pilot Card (Checklist C1.2 of Bridge Procedures Guide);\n> The pilotage plan and the circumstances when deviation from the plan may be required.\n> Any amendments to the plan should be agreed, and any changes in individual Bridge Team responsibilities made before pilotage\ncommences.\n> Updates on local conditions such as weather, depth of water, tides and tidal streams.\n> An update on traffic conditions.\n> Ship’s dimensions and manoeuvring information should be provided in the form of the Wheelhouse Poster (Checklist C1.3 of\nBridge Procedures Guide). A manoeuvring booklet containing more detailed information should also be available on the bridge.\n> Any unusual ship handling characteristics and machinery, navigational equipment and crew limitations that could affect the safe\nconduct of pilotage and berthing.\n> Information on berthing arrangements including the use, characteristics and number of tugs, mooring boats, mooring\narrangements and other external facilities.\n> Contingency plans should also be considered. These should identify possible abort points in the event of a malfunction or a\nshipboard emergency; and\n> Formal confirmation of the working language.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":28,"source_page_end":28,"raw_source_text":"Has the Master/Pilot information exchange been taking place effectively and is the standard pilot card\nbeing completed as required? (V)\nGuide to Inspection\nThe Officer should record the time when the Master/Pilot information exchange is completed. If different, the time of the transfer\nof conn between the Master and Pilot should also be recorded. Additionally, the time of the transfer of conn between Pilots, and if\napplicable, between the Pilot and Master on an outbound passage, should be recorded.\nThe Pilot card should clearly indicate whether a power limiter is engaged, the time necessary to override the power limitation systems,\nand the ship’s maximum power capacity, both with and without the application of the limiter.\nWhile navigating in pilotage waters, the main engine shall be readily available to respond immediately to the full range of manoeuvring\ncommands as outlined in the Pilot card.\nThe pilot and the Master should exchange information regarding the pilot’s intentions, the ship’s characteristics, and operational factor\nas soon as practicable after the pilot has boarded the ship.\nFor an effective Master/Pilot information exchange, use should be made of the MPX checklist (Checklist C1.1 of Bridge Procedures\nGuide). It is essential that the MPX result in clear and effective communication and should cover:\n> Presentation of a completed standard Pilot Card (Checklist C1.2 of Bridge Procedures Guide);\n> The pilotage plan and the circumstances when deviation from the plan may be required.\n> Any amendments to the plan should be agreed, and any changes in individual Bridge Team responsibilities made before pilotage\ncommences.\n> Updates on local conditions such as weather, depth of water, tides and tidal streams.\n> An update on traffic conditions.\n> Ship’s dimensions and manoeuvring information should be provided in the form of the Wheelhouse Poster (Checklist C1.3 of\nBridge Procedures Guide). A manoeuvring booklet containing more detailed information should also be available on the bridge.\n> Any unusual ship handling characteristics and machinery, navigational equipment and crew limitations that could affect the safe\nconduct of pilotage and berthing.\n> Information on berthing arrangements including the use, characteristics and number of tugs, mooring boats, mooring\narrangements and other external facilities.\n> Contingency plans should also be considered. These should identify possible abort points in the event of a malfunction or a\nshipboard emergency; and\n> Formal confirmation of the working language.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.7","internal_question_no":"03A.007","question_sort_key":3100700.021,"question_text":"Has the vessel’s manager produced a guideline for under keel clearance and air draft clearance?","guide_to_inspection":"Inspector should verify the accuracy of the UKC calculation.\nThe UKC policy should incorporate the minimum allowed under-keel clearance for both coastal, river navigation and\nwhile alongside, including guidance on the action to be taken in shallow water to ensure the minimum clearance is\nmaintained. The required minimum air draft for passing under bridges or overhead cables must be defined by the\nvessel’s manager. The vessel’s manager’s guidelines shall cover the calculation of Dynamic Under Keel Clearance\n(DUKC) and air draft. The UKC Calculation on board shall take CATZOC information in the account.\nThe CATZOC value highlights the accuracy of data presented on charts.\nWith six categories, it informs the user about how far they can rely on the chart when planning a passage or\nconducting navigation.\nCompanies should set out their minimum UKC and procedures for operating within different values of CATZOC in the SMS.\n(Bridge Procedures Guide ,2022)\nFor each Zone of Confidence (ZOC) value, reference shall be made to either Hydrographic publication UKHO NP 5012\nor figure 3.8 of the Bridge Procedures Guide 2022.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":29,"source_page_end":29,"raw_source_text":"Has the vessel’s manager produced a guideline for under keel clearance and air draft clearance? (M)\nGuide to Inspection\nInspector should verify the accuracy of the UKC calculation.\nThe UKC policy should incorporate the minimum allowed under-keel clearance for both coastal, river navigation and\nwhile alongside, including guidance on the action to be taken in shallow water to ensure the minimum clearance is\nmaintained. The required minimum air draft for passing under bridges or overhead cables must be defined by the\nvessel’s manager. The vessel’s manager’s guidelines shall cover the calculation of Dynamic Under Keel Clearance\n(DUKC) and air draft. The UKC Calculation on board shall take CATZOC information in the account.\nThe CATZOC value highlights the accuracy of data presented on charts.\nWith six categories, it informs the user about how far they can rely on the chart when planning a passage or\nconducting navigation.\nCompanies should set out their minimum UKC and procedures for operating within different values of CATZOC in the SMS.\n(Bridge Procedures Guide ,2022)\nFor each Zone of Confidence (ZOC) value, reference shall be made to either Hydrographic publication UKHO NP 5012\nor figure 3.8 of the Bridge Procedures Guide 2022.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.8","internal_question_no":"03A.008","question_sort_key":3100800.022,"question_text":"Are the fire and safety rounds being conducted at the end of each watch?","guide_to_inspection":"No other activity or duties should be allowed to interfere with keeping a proper look-out. The officer of watch should\nnot be the sole look-out during hours of darkness.\n(Bridge Procedures Guide, 2022)\nIn areas not covered by a fire detection system, regular fire patrols should be conducted. Such patrols should avoid\nusing the bridge lookout during the hours of darkness.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":29,"source_page_end":29,"raw_source_text":"Are the fire and safety rounds being conducted at the end of each watch? (V)\nGuide to Inspection\nNo other activity or duties should be allowed to interfere with keeping a proper look-out. The officer of watch should\nnot be the sole look-out during hours of darkness.\n(Bridge Procedures Guide, 2022)\nIn areas not covered by a fire detection system, regular fire patrols should be conducted. Such patrols should avoid\nusing the bridge lookout during the hours of darkness.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.9","internal_question_no":"03A.009","question_sort_key":3100900.023,"question_text":"Does the manning level in the bridge at all stages of the voyage and anchor meet or exceed that required by the Bridge Manning Matrix and are lookout arrangements adequate?","guide_to_inspection":"The recommended form and example of the Bridge Manning Matrix is contained in the Bridge Procedures Guide. The\nBridge Manning Matrix shall be posted in the Bridge.\nUnder the STCW Code, the Officer of the Watch (OOW) may, in certain circumstances, be the sole look-out in daylight\nconditions. Clear guidance on the conduct of sole look-out should be included in the SMS.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":29,"source_page_end":29,"raw_source_text":"Does the manning level in the bridge at all stages of the voyage and anchor meet or exceed that required by\nthe Bridge Manning Matrix and are lookout arrangements adequate? (V)\nGuide to Inspection\nThe recommended form and example of the Bridge Manning Matrix is contained in the Bridge Procedures Guide. The\nBridge Manning Matrix shall be posted in the Bridge.\nUnder the STCW Code, the Officer of the Watch (OOW) may, in certain circumstances, be the sole look-out in daylight\nconditions. Clear guidance on the conduct of sole look-out should be included in the SMS.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.10","internal_question_no":"03A.010","question_sort_key":3101000.024,"question_text":"Is navigation equipment in good order?","guide_to_inspection":"If the magnetron of radar has not been changed as per manufacture recommendation but mitigation measures are in\nplace, such as regular Performance Monitor tests per watch and maintaining a spare magnetron as essential spares,\nthe inspector should not record the finding but should enter a comment detailing when the last magnetron change\noccurred and what mitigation measures were in place.\nThe ship-borne navigational systems and equipment shall comply with SOLAS Chapter V Regulation 19.\nThe navigation equipment when fitted in the bridge, regardless of whether a vessel is required by legislation to carry\nsuch equipment, should be operational.\nRandom checks should be made to ensure that equipment is operational.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":29,"source_page_end":29,"raw_source_text":"Is navigation equipment in good order? (V)\nGuide to Inspection\nIf the magnetron of radar has not been changed as per manufacture recommendation but mitigation measures are in\nplace, such as regular Performance Monitor tests per watch and maintaining a spare magnetron as essential spares,\nthe inspector should not record the finding but should enter a comment detailing when the last magnetron change\noccurred and what mitigation measures were in place.\nThe ship-borne navigational systems and equipment shall comply with SOLAS Chapter V Regulation 19.\nThe navigation equipment when fitted in the bridge, regardless of whether a vessel is required by legislation to carry\nsuch equipment, should be operational.\nRandom checks should be made to ensure that equipment is operational.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.11","internal_question_no":"03A.011","question_sort_key":3101100.025,"question_text":"Are navigation lights, emergency navigation lights, shapes and signalling equipment in working order?","guide_to_inspection":"The OOW is responsible for ensuring that the navigation lights, emergency navigation lights and signalling equipment\nare in working order and are ready for immediate use at all times. The condition of lights, flags and shapes should be\nchecked at regular intervals. Sound signalling equipment should be checked daily and maintained in an operational\ncondition. (Bridge Procedures Guide, 2022)\nA procedure for testing of the navigation light failure alarm should be posted on the bridge.\nThe signalling lamp should have 3 spare bulbs and a portable battery pack.\n(PERFORMANCE STANDARDS FOR DAYLIGHT SIGNALLING LAMPS, 2000)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":30,"source_page_end":30,"raw_source_text":"Are navigation lights, emergency navigation lights, shapes and signalling equipment in working order? (V)\nGuide to Inspection\nThe OOW is responsible for ensuring that the navigation lights, emergency navigation lights and signalling equipment\nare in working order and are ready for immediate use at all times. The condition of lights, flags and shapes should be\nchecked at regular intervals. Sound signalling equipment should be checked daily and maintained in an operational\ncondition. (Bridge Procedures Guide, 2022)\nA procedure for testing of the navigation light failure alarm should be posted on the bridge.\nThe signalling lamp should have 3 spare bulbs and a portable battery pack.\n(PERFORMANCE STANDARDS FOR DAYLIGHT SIGNALLING LAMPS, 2000)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.12","internal_question_no":"03A.012","question_sort_key":3101200.026,"question_text":"Are navigation officers familiar with the company procedure for the use of the Bridge Navigational Watch Alarm System (BNWAS), were records available to demonstrate that it had been operated when the ship was underway and at anchor, and tested in accordance with the procedure?","guide_to_inspection":"The BNWAS must be operational whenever the ship is underway and should be used at anchor. Use of BNWAS modes\n(automatic, manual, on and off) and procedures for ensuring correct operation should be incorporated in the company\nnavigation procedure. The operation of the BNWAS should be part of the departure checklist and a key,if supplied, should\nbe kept with the Master when switched on.\n(Bridge Procedures Guide, 2022)\nThe means of selecting the Operational Mode and the duration of the Dormant Period should be security protected so\nthat access to these controls should be restricted to the Master only. The BNWAS should be powered from the ship’s\nmain power supply. The malfunction indication, and all elements of the Emergency Call facility, if incorporated, should be\npowered from a battery-maintained supply.\nIf a malfunction of, or power supply failure to, the BNWAS is detected, this should be indicated. Means shall be provided to\nallow the repeat of this indication on a central alarm panel if fitted.\n(Resolution MSC.128 (75) Performance Standard For a BNWAS, 2002)\nThe vessel manager should establish procedures detailing when the BNWAS should be operational, the personnel\nresponsible for its activation, and the activation process itself. Additionally, the procedures should include measures to\nsafeguard the system against unauthorised deactivation. They should also specify the actions to be taken if a BNWAS\nstage 2 or 3 alarm is triggered, as well as the periodic tests and checks necessary to ensure the system’s proper\nfunctioning.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":30,"source_page_end":30,"raw_source_text":"Are navigation officers familiar with the company procedure for the use of the Bridge Navigational Watch\nAlarm System (BNWAS), were records available to demonstrate that it had been operated when the ship\nwas underway and at anchor, and tested in accordance with the procedure? (V)\nGuide to Inspection\nThe BNWAS must be operational whenever the ship is underway and should be used at anchor. Use of BNWAS modes\n(automatic, manual, on and off) and procedures for ensuring correct operation should be incorporated in the company\nnavigation procedure. The operation of the BNWAS should be part of the departure checklist and a key,if supplied, should\nbe kept with the Master when switched on.\n(Bridge Procedures Guide, 2022)\nThe means of selecting the Operational Mode and the duration of the Dormant Period should be security protected so\nthat access to these controls should be restricted to the Master only. The BNWAS should be powered from the ship’s\nmain power supply. The malfunction indication, and all elements of the Emergency Call facility, if incorporated, should be\npowered from a battery-maintained supply.\nIf a malfunction of, or power supply failure to, the BNWAS is detected, this should be indicated. Means shall be provided to\nallow the repeat of this indication on a central alarm panel if fitted.\n(Resolution MSC.128 (75) Performance Standard For a BNWAS, 2002)\nThe vessel manager should establish procedures detailing when the BNWAS should be operational, the personnel\nresponsible for its activation, and the activation process itself. Additionally, the procedures should include measures to\nsafeguard the system against unauthorised deactivation. They should also specify the actions to be taken if a BNWAS\nstage 2 or 3 alarm is triggered, as well as the periodic tests and checks necessary to ensure the system’s proper\nfunctioning.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.13","internal_question_no":"03A.013","question_sort_key":3101300.027,"question_text":"Where fitted are the standard magnetic compass, gyro compass and Global Navigation Satellite System compass, operational, adjusted and properly maintained?","guide_to_inspection":"Record a Finding if the gyro compass was not serviced as per manufa\ncturer recommendation.\nThe magnetic compass is generally fitted above the navigating bridge on the centreline and fitted with a periscope so that the\ncompass is readable from the helmsman’s position. Where the magnetic compass is needed to provide heading outputs to\nother bridge systems, a transmitting magnetic compass (TMC) is fitted. TMC outputs should be corrected for compass error\nand the TMC should be tested once a week.\nA compass deviation card should be maintained on the bridge. The deviation will need to be determined and the compass\nadjusted at intervals during the ship’s life, particularly after any major steel conversion work to the ship. Caution should be\nobserved when using the magnetic compass on ships that carry or have recently carried magnetic cargoes such as iron ore\nand steel.\nCompass safe distances are specified on all electrical bridge equipment and provide the minimum distances from the\nmagnetic compass that equipment can be installed.\nA TMC may have variation automatically applied. However, this correction will not include deviation. When correcting TMC\noutputs for compass error, care should be taken to ensure that the correct values for variation and deviation are applied.\nThe gyro compass should be run continuously. Should a gyro compass stop for any reason, it should be restarted and\nsubsequently regularly checked and only relied on again when it has “settled” and the error is known.\nWhere the gyro has no direct speed log or position input, manual corrections should be made as required.\nThe gyro will support a number of repeaters, including a required repeater at the emergency steering position. Gyro repeaters\non the bridge should be checked against the main gyro at least once per watch and after significant manoeuvring. Other\nrepeaters should be checked frequently.\nA Global Navigation Satellite System (GNSS) compass provides an alternative to a gyro compass as a non-magnetic\ntransmitting heading device able to provide heading data to AIS, radar and automatic plotting aids. A GNSS compass or\nequivalent is required on ships navigating in polar waters at latitudes above 80 degrees. (Bridge Procedures Guide, 2022)\nIf the observations for a magnetic compass on a vessel show a deviation of the compass on any heading of more than 5\ndegrees, the compass must be adjusted by a qualified compass adjuster or the Master of the vessel to correct the deviation.\nIf the compass is adjusted by the Master, RightShip recommends that the compass adjustment be checked by a qualified\ncompass adjuster at the next available opportunity.\nAll magnetic compasses shall be swung and adjusted at least:\n> Every two years.\n> After dry docking; or\n> After significant structural work.\n(BS ISO 25862:2019, 2019)\nWhere flag States have their own requirements then these should be followed.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":30,"source_page_end":31,"raw_source_text":"Where fitted are the standard magnetic compass, gyro compass and Global Navigation Satellite System\ncompass, operational, adjusted and properly maintained? (V & M)\nGuide to Inspection\nRecord a Finding if the gyro compass was not serviced as per manufa\ncturer recommendation.\nThe magnetic compass is generally fitted above the navigating bridge on the centreline and fitted with a periscope so that the\ncompass is readable from the helmsman’s position. Where the magnetic compass is needed to provide heading outputs to\nother bridge systems, a transmitting magnetic compass (TMC) is fitted. TMC outputs should be corrected for compass error\nand the TMC should be tested once a week.\nA compass deviation card should be maintained on the bridge. The deviation will need to be determined and the compass\nadjusted at intervals during the ship’s life, particularly after any major steel conversion work to the ship. Caution should be\nobserved when using the magnetic compass on ships that carry or have recently carried magnetic cargoes such as iron ore\nand steel.\nCompass safe distances are specified on all electrical bridge equipment and provide the minimum distances from the\nmagnetic compass that equipment can be installed.\nA TMC may have variation automatically applied. However, this correction will not include deviation. When correcting TMC\noutputs for compass error, care should be taken to ensure that the correct values for variation and deviation are applied.\nThe gyro compass should be run continuously. Should a gyro compass stop for any reason, it should be restarted and\nsubsequently regularly checked and only relied on again when it has “settled” and the error is known.\nWhere the gyro has no direct speed log or position input, manual corrections should be made as required.\nThe gyro will support a number of repeaters, including a required repeater at the emergency steering position. Gyro repeaters\non the bridge should be checked against the main gyro at least once per watch and after significant manoeuvring. Other\nrepeaters should be checked frequently.\nA Global Navigation Satellite System (GNSS) compass provides an alternative to a gyro compass as a non-magnetic\ntransmitting heading device able to provide heading data to AIS, radar and automatic plotting aids. A GNSS compass or\nequivalent is required on ships navigating in polar waters at latitudes above 80 degrees. (Bridge Procedures Guide, 2022)\nIf the observations for a magnetic compass on a vessel show a deviation of the compass on any heading of more than 5\ndegrees, the compass must be adjusted by a qualified compass adjuster or the Master of the vessel to correct the deviation.\nIf the compass is adjusted by the Master, RightShip recommends that the compass adjustment be checked by a qualified\ncompass adjuster at the next available opportunity.\nAll magnetic compasses shall be swung and adjusted at least:\n> Every two years.\n> After dry docking; or\n> After significant structural work.\n(BS ISO 25862:2019, 2019)\nWhere flag States have their own requirements then these should be followed.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.14","internal_question_no":"03A.014","question_sort_key":3101400.028,"question_text":"Where manual steering is engaged, is the change over from auto steering, and vice versa, recorded?","guide_to_inspection":"Times and locations of engaging hand steering should be recorded in the deck logbook or bell book.\nManual steering should be used whenever appropriate including in:\n> Areas of high traffic density.\n> Conditions of restricted visibility; and\n> Any other potentially hazardous situations and particularly when an automatic steering system may provide\ninsufficient control.\n> Manual steering should be tested once per watch as per the checklist C2.1 of the Bridge Procedures Guide.\n(Bridge ProceduresGuide, 2022)\nExamples of other potentially hazardous situations are river transits and when navigating through restricted waters.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":31,"source_page_end":31,"raw_source_text":"Where manual steering is engaged, is the change over from auto steering, and vice versa, recorded? (V)\nGuide to Inspection\nTimes and locations of engaging hand steering should be recorded in the deck logbook or bell book.\nManual steering should be used whenever appropriate including in:\n> Areas of high traffic density.\n> Conditions of restricted visibility; and\n> Any other potentially hazardous situations and particularly when an automatic steering system may provide\ninsufficient control.\n> Manual steering should be tested once per watch as per the checklist C2.1 of the Bridge Procedures Guide.\n(Bridge ProceduresGuide, 2022)\nExamples of other potentially hazardous situations are river transits and when navigating through restricted waters.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.15","internal_question_no":"03A.015","question_sort_key":3101500.029,"question_text":"Are deck officers familiar with the procedure to preserve the VDR data in the event of an incident and is there a company policy within the SMS relating to the playback of VDR data?","guide_to_inspection":"Watch-keeping officers should understand and be familiar with the procedures for preserving records as required by the SMS.\nCompany policy relating to the playback of VDR data should be contained within the SMS. Playback of VDR data may provide a\ntool for analysing the performance of the Bridge Team. A mistake as long as it is not intentional or caused by carelessness, should\nnormally be treated as a learning opportunity. A ‘just’ culture should give personnel the confidence to admit any mistakes or ‘near\nmisses’, and this leads to a safer working environment.\nTesting is required annually and should always be carried out following repair or maintenance work to the VDR or to any source\nproviding data to the VDR.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":31,"source_page_end":31,"raw_source_text":"Are deck officers familiar with the procedure to preserve the VDR data in the event of an incident and is\nthere a company policy within the SMS relating to the playback of VDR data? (V)\nGuide to Inspection\nWatch-keeping officers should understand and be familiar with the procedures for preserving records as required by the SMS.\nCompany policy relating to the playback of VDR data should be contained within the SMS. Playback of VDR data may provide a\ntool for analysing the performance of the Bridge Team. A mistake as long as it is not intentional or caused by carelessness, should\nnormally be treated as a learning opportunity. A ‘just’ culture should give personnel the confidence to admit any mistakes or ‘near\nmisses’, and this leads to a safer working environment.\nTesting is required annually and should always be carried out following repair or maintenance work to the VDR or to any source\nproviding data to the VDR.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.16","internal_question_no":"03A.016","question_sort_key":3101600.03,"question_text":"Is a chart and publication management system being implemented to ensure that all charts, nautical publications, and other publications on board are current, maintained and up to date?","guide_to_inspection":"RightShip recommends that a shore-based company be engaged to provide navigation support services including ENC’s, paper\ncharts and marine publications, so as to ensure that those on board are up to date with the latest edition available.\nUse of a chart and publication management system will help to ensure that charts and publications are effectively maintained.\nA management system should record the charts, publications and licences/ permits carried, and when the charts and other\npublications were last corrected. Licensees and permits are available from the hydrographic office that produced the ENC or RNC.\nLicensing arrangements usually include:\n> Pre-pay licensing based on intended use. Normally licenses and permits are specific to a ship and typically allow a chart to\nbe viewed for a period of 3,6 or 12 months on that ship;or\n> Dynamic or pay as you sail(PAYS) licensing based on actual passage. Ships have access to all charts for planning\npurposes but only pay for charts that they use during navigation.\nLicenses and permits should be managed using the ship’s chart management system.\n(Bridge Procedures Guide, 2022)\nThe Weekly Notice to Mariners Section VIII and the README file contains important safety information relating to ENCs and ECDIS.\nThe file is included on all ENC media but some ECDIS may not be able to display it; it can however be read on any standalone PC.\nThe vessel’s officers should all be aware of the recent content of the file and be able to demonstrate the practical application of the\ninformation.\n(Admiralty Guide to ECDIS Implementation, Policy and Procedures, 2016)\nThe chart and publication management system shall cover the ENC management and correction process, including safety\nmeasures, to avoid viruses.The NP133C Admiralty ENC Maintenance Record book, or equivalent software, should be available on\nboard.\nAn effective ENC management system should be in place on board to record ECDIS identification numbers and when licences/\npermits were received on board and should include a record of when the ENCs were last updated. This is generally part of ECDI\nsoftware logging.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":32,"source_page_end":32,"raw_source_text":"Is a chart and publication management system being implemented to ensure that all charts, nautical\npublications, and other publications on board are current, maintained and up to date? (V & M)\nGuide to Inspection\nRightShip recommends that a shore-based company be engaged to provide navigation support services including ENC’s, paper\ncharts and marine publications, so as to ensure that those on board are up to date with the latest edition available.\nUse of a chart and publication management system will help to ensure that charts and publications are effectively maintained.\nA management system should record the charts, publications and licences/ permits carried, and when the charts and other\npublications were last corrected. Licensees and permits are available from the hydrographic office that produced the ENC or RNC.\nLicensing arrangements usually include:\n> Pre-pay licensing based on intended use. Normally licenses and permits are specific to a ship and typically allow a chart to\nbe viewed for a period of 3,6 or 12 months on that ship;or\n> Dynamic or pay as you sail(PAYS) licensing based on actual passage. Ships have access to all charts for planning\npurposes but only pay for charts that they use during navigation.\nLicenses and permits should be managed using the ship’s chart management system.\n(Bridge Procedures Guide, 2022)\nThe Weekly Notice to Mariners Section VIII and the README file contains important safety information relating to ENCs and ECDIS.\nThe file is included on all ENC media but some ECDIS may not be able to display it; it can however be read on any standalone PC.\nThe vessel’s officers should all be aware of the recent content of the file and be able to demonstrate the practical application of the\ninformation.\n(Admiralty Guide to ECDIS Implementation, Policy and Procedures, 2016)\nThe chart and publication management system shall cover the ENC management and correction process, including safety\nmeasures, to avoid viruses.The NP133C Admiralty ENC Maintenance Record book, or equivalent software, should be available on\nboard.\nAn effective ENC management system should be in place on board to record ECDIS identification numbers and when licences/\npermits were received on board and should include a record of when the ENCs were last updated. This is generally part of ECDI\nsoftware logging.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"03A","section_number":3,"section_letter":"A","section_title":"Navigation","printed_question_no":"3.17","internal_question_no":"03A.017","question_sort_key":3101700.031,"question_text":"Were appropriate charts and publication used for the previous voyage?","guide_to_inspection":"Vessel should obtain licences for and use the largest scale of ENCs available for all stages of each passage.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nOnly up-to-date official charts and publications should be used for the appraisal, planning, execution, and monitoring of a\npassage plan.\nFor coastal and pilotage planning and for plotting each course alteration point, large scale charts should be used. Any additional\ncharts and publications needed for the intended passage should be identified and obtained before departure.\nFor ocean passage planning and open water legs, the largest scale charts that are appropriate should be used\n(Sections 2.3.1 Bridge Procedures Guide, 2016)\nPhotocopied/scanned copies of official paper charts (whether subsequently corrected to latest notices to mariner or not) are\nNOT regarded as satisfying the SOLAS chart carriage requirement.\nThe following publications shall be available on board and referred to when the primary means of navigation is ECDIS:\n> NP 231 Admiralty Guide to the Practical Use of ENC’s.\n> NP 5012 Admiralty Guide to ENC Symbols Used in ECDIS\nThe Seafarers Handbook for Australian Waters (AHP20) is an official nautical publication providing mariners with important\nmaritime information from various Australian government agencies, under the cover of one combined reference. It is expected\nthat all commercial vessels operating in Australian waters carry and refer to the publication.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":32,"source_page_end":32,"raw_source_text":"Were appropriate charts and publication used for the previous voyage? (V)\nGuide to Inspection\nVessel should obtain licences for and use the largest scale of ENCs available for all stages of each passage.\n(Recommendations on Usage of ECDIS and Preventing Incident, 2020)\nOnly up-to-date official charts and publications should be used for the appraisal, planning, execution, and monitoring of a\npassage plan.\nFor coastal and pilotage planning and for plotting each course alteration point, large scale charts should be used. Any additional\ncharts and publications needed for the intended passage should be identified and obtained before departure.\nFor ocean passage planning and open water legs, the largest scale charts that are appropriate should be used\n(Sections 2.3.1 Bridge Procedures Guide, 2016)\nPhotocopied/scanned copies of official paper charts (whether subsequently corrected to latest notices to mariner or not) are\nNOT regarded as satisfying the SOLAS chart carriage requirement.\nThe following publications shall be available on board and referred to when the primary means of navigation is ECDIS:\n> NP 231 Admiralty Guide to the Practical Use of ENC’s.\n> NP 5012 Admiralty Guide to ENC Symbols Used in ECDIS\nThe Seafarers Handbook for Australian Waters (AHP20) is an official nautical publication providing mariners with important\nmaritime information from various Australian government agencies, under the cover of one combined reference. It is expected\nthat all commercial vessels operating in Australian waters carry and refer to the publication.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ11$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 1/15 imported.' AS result,
  '02A.001' AS chunk_first_question,
  '03A.017' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
